def build_url(base_url, path):
    # Remove trailing slash from base_url if present
    if base_url.endswith('/'):
        base_url = base_url[:-1]

    # Add leading slash to path if not present
    if not path.startswith('/'):
        path = '/' + path

    return base_url + path

